import React, { useContext, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { Dropdown, Container } from 'react-bootstrap'; 
// Contextos
import { AuthContext } from '../context/AuthContext';
import { CartContext } from '../context/CartContext';
import { SettingsContext } from '../context/SettingsContext'; 
// Componentes
import SearchBox from './SearchBox';
import HeaderSkeleton from './HeaderSkeleton'; 
// Estilos (CSS Puro)
import styles from './Header.module.css'; 

const Header = () => {
  const navigate = useNavigate();
  const { userInfo: user, logout, loading: authLoading } = useContext(AuthContext); 
  const { cartItems, isItemJustAdded } = useContext(CartContext);
  const { settings, loading: settingsLoading } = useContext(SettingsContext);

  useEffect(() => {
    // Aplicar el color de acento a las variables CSS globales
    if (settings?.accentColor) {
      document.documentElement.style.setProperty('--cta-color', settings.accentColor);
    }
  }, [settings]);

  const logoutHandler = () => {
    logout();
    navigate('/login');
  };

  const totalCartItems = cartItems.reduce((acc, item) => acc + item.qty, 0); 
  const canAccessAdminPanel = user?.permissions?.includes('access:admin_panel');
  const isLoading = authLoading || settingsLoading;

  if (isLoading) {
     return <HeaderSkeleton />;
  }

  // --- LÓGICA DEL LOGO ---
  // Texto base: "Tecnotitlán"
  const logoText = "Tecnotitlán";
  // Inyección del acento: Reemplazamos 'á' por el span con la clase .accent
  const logoHtml = logoText.replace('á', `<span class="${styles.accent}">á</span>`);

  return (
    <header className={styles.header}>
      <Container> 
        <div className="d-flex justify-content-between align-items-center h-100"> 
          
          {/* 1. LOGO + TEXTO */}
          <Link to="/" className={styles.logoContainer}> 
            {/* Imagen del Logo (Opcional) */}
            {settings?.logoUrl && (
              <img 
                src={settings.logoUrl} 
                alt="Tecnotitlán" 
                className={styles.logoImage} 
                onError={(e) => { e.target.style.display = 'none'; }} 
              />
            )}
            
            {/* Texto del Logo */}
            <div className={styles.logoText}>
                <span dangerouslySetInnerHTML={{ __html: logoHtml }}></span>
            </div>
          </Link>

          {/* 2. BUSCADOR (Visible en Desktop) */}
          <div className="d-none d-lg-block w-50 px-4">
            <SearchBox /> 
          </div>

          {/* 3. NAVEGACIÓN DERECHA */}
          <nav className="d-flex align-items-center gap-3">
            
            {/* Carrito */}
            <Link 
              to="/cart" 
              className={`${styles.cartLink} ${isItemJustAdded ? styles.pulse : ''}`}
            >
              <i className={`fas fa-shopping-cart ${styles.cartIcon}`}></i>
              <span className={styles.cartLabel}>Carrito</span>
              {totalCartItems > 0 && (
                <span className={styles.cartBadge}>{totalCartItems}</span>
              )}
            </Link>

            {/* Usuario / Login */}
            {user ? (
              <Dropdown align="end">
                <Dropdown.Toggle as="a" className={styles.navLink}>
                  <div className={styles.avatarContainer}>
                    <i className="fas fa-user text-white" style={{ fontSize: '0.8rem' }}></i>
                  </div>
                  <span className="d-none d-md-inline">{user.name}</span>
                </Dropdown.Toggle>

                <Dropdown.Menu className="shadow-lg border-0 rounded-3 mt-2">
                  <Dropdown.Item as={Link} to="/profile">Perfil</Dropdown.Item>
                  {canAccessAdminPanel && (
                    <Dropdown.Item as={Link} to="/admin/dashboard">Panel Admin</Dropdown.Item>
                  )}
                  <Dropdown.Divider />
                  <Dropdown.Item onClick={logoutHandler} className="text-danger">Cerrar Sesión</Dropdown.Item>
                </Dropdown.Menu>
              </Dropdown>
            ) : (
              <Link to="/login" className={styles.navLink}>
                <i className="fas fa-user"></i> 
                <span className="d-none d-md-inline ms-1">Entrar</span>
              </Link>
            )}
          </nav>

        </div>
        
        {/* Buscador Móvil (Debajo) */}
        <div className="d-lg-none mt-3 pb-2">
          <SearchBox />
        </div>
      </Container>
    </header>
  );
};

export default Header;
